const grpc = require('grpc');
const protoLoader = require('@grpc/proto-loader');

// Load the gRPC service definition
const packageDefinition = protoLoader.loadSync('path/to/your/service.proto', {
  keepCase: true,
  longs: String,
  enums: String,
  defaults: true,
  oneofs: true
});

const yourService = grpc.loadPackageDefinition(packageDefinition).your_service;

// Create a gRPC client
const client = new yourService.YourService('backend-service-address:port', grpc.credentials.createInsecure());

function forwardHeadersToGrpc(metadata) {
  const customHeaders = ['user-agent', 'x-forwarded-for'];
  customHeaders.forEach(header => {
    if (metadata.has(header)) {
      metadata.add(header, metadata.get(header));
    }
  });
}

// Create an HTTP server to receive requests
const http = require('http');
const server = http.createServer((req, res) => {
  const metadata = new grpc.Metadata();
  
  // Forward custom headers from HTTP request to gRPC metadata
  forwardHeadersToGrpc(metadata);
  
  // Call the gRPC service method with the forwarded metadata
  client.yourMethod({}, metadata, (err, response) => {
    if (err) {
      res.statusCode = err.code || 500;
      res.end(err.message);
    } else {
      res.statusCode = 200;
      res.end(JSON.stringify(response));
    }
  });
});

